export const LIBRARY_BY_SLUG: Record<string, LibraryCard> = Object.fromEntries(
  CARD_LIBRARY.map((c) => [c.slug, c])
);

// Karty stejné sady (interní prolinkování v1.6.2 §2) - nahrazuje dřívější
// náhodné „související karty".
export function sameSection(slug: string): LibraryCard[] {
  const me = LIBRARY_BY_SLUG[slug];
  if (!me) return [];
  return CARD_LIBRARY.filter((c) => c.section === me.section && c.slug !== slug);
}
